scwin.today = $c.date.getServerDateTime($p, "yyyyMMdd");
scwin.curDate = scwin.today.substring(0, 6);

//hidden
scwin.hid_FromDate = "";
scwin._gb = "";
scwin.onpageload = function () {
  const codeOptions = [{
    grpCd: "CO012",
    compID: "lc_unit"
  }];
  // console.log(" codeOptions : "+ JSON.stringify(codeOptions));
  $c.data.setCommonCode($p, codeOptions);
};
scwin.btn_reset_onclick = function (e) {
  $c.gus.cfInitObjects($p, table1, [ed_closeYmSt, ed_closeYmEnd, rd_transCargoClsCd, rd_schGroup]);
};
scwin.btn_search_onclick = function (e) {
  scwin.f_Retrieve();
};
scwin.btn_Sav2_onclick = function (e) {
  scwin.f_Save();
};
scwin.ondataload = function () {
  lc_unit.setSelectedIndex(1);
};
scwin.onUdcCompleted = function () {
  ed_closeYmSt.setValue(scwin.curDate);
  ed_closeYmEnd.setValue(scwin.curDate);
  ed_pCloseYm.setValue(scwin.curDate);
  lc_srchBookClsCd.setSelectedIndex(0);
  rd_schGroup.setValue("01"); //거래처번호기준
  rd_transCargoClsCd.setSelectedIndex(0);

  //디버그용 : 추후 삭제
  //ed_closeYmSt.setValue("202212");
  //ed_closeYmEnd.setValue("202212");
};
scwin.udc_BizDomCd_onclickEvent = function (e) {
  scwin.f_BizDomPopUp("1");
};
scwin.udc_acctDeptCd_onclickEvent = function (e) {
  scwin.f_openPopUp(ed_acctDeptCd, ed_acctDeptNm, '1', 'ALL');
};
scwin.udc_crn_onclickEvent = function (e) {
  scwin.f_openPopUp(ed_crn, ed_busiNm, '3', 'ALL');
};
scwin.udc_clntNo_onclickEvent = function (e) {
  scwin.f_openPopUp(ed_clntNo, ed_clntNm, '2', 'ALL');
};
scwin.sbm_search_submitdone = function (e) {
  //원본 데이터를 ds_deptProfitLossOriginal에 백업
  let originalData = ds_master.getAllJSON();
  ds_master_org.setJSON(originalData);
  let rowCnt = ds_master.getRowCount();
  if (rowCnt == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
  }
  ed_totalRows.setValue(rowCnt);
  scwin.f_changeUnit();
};
scwin.subTotal = function (val) {
  var ret = 0;
  var unit = 1;
  if (lc_unit.getValue() == "01") {
    unit = 1;
  } else if (lc_unit.getValue() == "02") {
    unit = 1000;
  } else if (lc_unit.getValue() == "03") {
    unit = 1000000;
  } else if (lc_unit.getValue() == "04") {
    unit = 100000000;
  }
  if (isFinite(Number(val) / unit)) {
    ret = Math.round(Number(val) / unit);
  }
  return ret;
};
scwin.sbm_search_submiterror = function (e) {};
scwin.udc_acctDeptCd_cb = function (rtnList) {
  scwin.f_resultPopUp(ed_acctDeptCd, ed_acctDeptNm, rtnList);
};
scwin.udc_clntNo_cb = function (rtnList) {
  scwin.f_resultPopUp(ed_clntNo, ed_clntNm, rtnList);
};
scwin.udc_crn_cb = function (rtnList) {
  scwin.f_resultPopUp(ed_crn, ed_busiNm, rtnList);
};

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->부서 , 2:조회->거래처(거래처)
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
  let pWhere;
  // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
  if (flag == "ALL") {
    cd = "";
    nm = "";
  } else {
    cd = orgObjCd.getValue();
    nm = orgObjNm.getValue();
  }
  switch (select_code) {
    // 조회조건용 수금부서 PopUp 호출(물류 귀속부서만 POPUP에 포함)
    case '1':
      // 				rtnList = cfCommonPopUp('retrieveAcctDeptCdInfo2',cd, nm,"T",null,null,null,null,",,0,100,","450","500",null,null); // 귀속부서		

      pWhere = ed_closeYmSt.getValue().substring(0, 4) + ",,,,,,,,," + "000";
      udc_acctDeptCd.setSelectId("retrieveAcctDeptCdInfo");
      udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_cb, cd, nm, "T", null, null, null, null, pWhere, "450", "500", null, null); // 귀속부서	
      break;
    case '2':
      udc_clntNo.setSelectId("retrieveClntList");
      udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_cb, cd, nm, "T", null, null, null, null, null, "450", "500", null, null); // 거래처
      break;
    case '3':
      udc_crn.setSelectId("retrieveCrnInfo");
      udc_crn.cfCommonPopUp(scwin.udc_crn_cb, cd, nm, "T", null, null, null, null, null, "450", "500", null, null); // 사업자
      break;
    default:
      $c.gus.cfAlertMsg($p, "잘못된 Function호출 입니다. 관리자에게 문의하시기 바랍니다.");
      break;
  }
};

//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.f_resultPopUp = function (orgObjCd, orgObjNm, rtnList) {
  if (rtnList != null) {
    if (rtnList[0] == "N/A") return;
    orgObjCd.setValue(rtnList[0]); // 코드값
    orgObjNm.setValue(rtnList[1]); // 코드명
    orgObjCd.options.hidVal = rtnList[0]; // HIDDEN 코드값
    orgObjNm.options.hidVal = rtnList[1]; // HIDDEN 코드명
  } else {
    orgObjCd.setValue("");
    orgObjNm.setValue("");
    orgObjCd.options.hidVal = "";
    orgObjNm.options.hidVal = "";
  }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  let ret;
  // 조회조건 필수사항 체크
  ret = await $c.gus.cfValidate($p, [ed_closeYmSt, ed_closeYmEnd]);
  if (!ret) {
    return;
  }
  scwin.f_SetGridFormat();
  dma_search.set("bookClsCd", lc_srchBookClsCd.getValue());
  dma_search.set("closeYmSt", ed_closeYmSt.getValue());
  dma_search.set("closeYmEnd", ed_closeYmEnd.getValue());
  dma_search.set("acctDeptCd", ed_acctDeptCd.getValue());
  dma_search.set("clntNo", ed_clntNo.getValue());
  dma_search.set("bizDomCd", ed_BizDomCd.getValue());
  dma_search.set("schGroup", rd_schGroup.getValue());
  dma_search.set("crn", ed_crn.getValue());
  dma_search.set("transCargoClsCd", rd_transCargoClsCd.getValue());
  dma_search.set("pCloseYm", ed_pCloseYm.getValue());
  dma_search.set("pBizDomCd", ed_pBizDomCd.getValue());
  $c.sbm.execute($p, sbm_search);
};

