  // format += "<c> id=marginalProfits      name=한계이익         width=90 align=right sort=true dec=0 sumText=@sum </c>";
  // format += "<c> id=directFixCostAmt     name=직접고정비      width=90 align=right sort=true dec=0 sumText=@sum </c>";
