scwin.f_Save = async function () {
  let ret;
  // 필수사항 체크
  ret = await $c.gus.cfValidate($p, [ed_pCloseYm, ed_pBizDomCd]);
  if (!ret) {
    return;
  }
  let str = ed_pCloseYm.getValue();
  str = str.substring(0, 4) + "년 " + str.substring(4, 6) + "월 사업영역 [" + ed_pBizDomNm.getValue() + "]";
  ret = await $c.win.confirm($p, str + " 거래처 손익실적을 생성하시겠습니까?");
  if (!ret) {
    return;
  }

  // dma_search 데이터맵에 각 컨트롤의 값을 세팅합니다.
  dma_search.setJSON({
    "bookClsCd": lc_srchBookClsCd.getValue(),
    // 장부구분
    "closeYmSt": ed_closeYmSt.getValue(),
    // 기준년월_시작
    "closeYmEnd": ed_closeYmEnd.getValue(),
    // 기준년월_종료
    "acctDeptCd": ed_acctDeptCd.getValue(),
    // 부서코드
    "clntNo": ed_clntNo.getValue(),
    // 거래처코드
    "bizDomCd": ed_BizDomCd.getValue(),
    // 사업영역코드
    "schGroup": rd_schGroup.getValue(),
    // 집계기준
    "crn": ed_crn.getValue(),
    // 사업자번호
    "transCargoClsCd": rd_transCargoClsCd.getValue(),
    // 구분
    "pCloseYm": ed_pCloseYm.getValue(),
    // 기준년월_프로시저
    "pBizDomCd": ed_pBizDomCd.getValue() // 사업영역코드_프로시저
  });
  $c.sbm.execute($p, sbm_create);
};
